/* src/logging.h */
#ifndef LOGGING_H
#define LOGGING_H
#include <stdio.h>
#include <string.h>

/* DANGER: This macro uses sprintf without bounds checking! */
/* The vulnerability is hidden inside the macro expansion */
#define LOG_MSG(buf, fmt, ...) do { \
    sprintf(buf, "[ECU] " fmt, ##__VA_ARGS__); \
} while(0)

/* Safe version for comparison */
#define LOG_MSG_SAFE(buf, sz, fmt, ...) do { \
    snprintf(buf, sz, "[ECU] " fmt, ##__VA_ARGS__); \
} while(0)

#endif

/* src/diag.c */
#include <stdio.h>
#include <string.h>
#include "logging.h"

/* UDS diagnostic handler - processes requests from external tool */
void handle_uds_request(const char *service_id, const char *data, size_t data_len) {
    char log_buf[64];    /* small buffer! */
    char response[256];

    /* line 35: VULNERABLE - LOG_MSG expands to sprintf(log_buf, ...) */
    /* If data contains long string, overflows 64-byte log_buf */
    LOG_MSG(log_buf, "UDS[%s]: %s", service_id, data);

    /* Process the request */
    if (strcmp(service_id, "0x22") == 0) {
        /* ReadDataByIdentifier */
        snprintf(response, sizeof(response), "OK: %.*s", (int)data_len, data);
    }

    /* line 42: VULNERABLE - log_buf may already be corrupted from overflow above */
    printf("%s\n", log_buf);
}

/* src/telemetry.c */
#include <stdio.h>
#include <string.h>
#include "logging.h"

void send_telemetry(int channel_id, float value) {
    char buf[128];  /* line 15: variable scope - not a vulnerability */

    /* line 20: SAFE - uses LOG_MSG_SAFE with sizeof(buf) */
    LOG_MSG_SAFE(buf, sizeof(buf), "CH%d=%.2f", channel_id, value);

    /* send buf to telemetry server... */
    printf("%s\n", buf);
}
